import{_ as t,o,c as a,ag as i}from"./chunks/framework.1N8rnUr9.js";const c=JSON.parse('{"title":"Embedded Video Player","description":"","frontmatter":{},"headers":[],"relativePath":"features/embedded-player.md","filePath":"features/embedded-player.md","lastUpdated":1775715475000}'),r={name:"features/embedded-player.md"};function s(l,e,n,d,u,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="embedded-video-player" tabindex="-1">Embedded Video Player <a class="header-anchor" href="#embedded-video-player" aria-label="Permalink to &quot;Embedded Video Player&quot;">​</a></h1><p>TubeBay uses a highly optimized, responsive video player to display your YouTube content on WooCommerce product pages. The player is built on top of the YouTube IFrame API to ensure compatibility and performance.</p><h2 id="player-features" tabindex="-1">Player Features <a class="header-anchor" href="#player-features" aria-label="Permalink to &quot;Player Features&quot;">​</a></h2><ul><li><strong>Responsive Design:</strong> Automatically adjusts to fit any screen size (desktop, tablet, mobile).</li><li><strong>SEO Optimized:</strong> Uses standard HTML5 structures that search engines can easily index.</li><li><strong>Fast Loading:</strong> Only loads the YouTube API when the player is needed, minimizing the impact on initial page load.</li></ul><h2 id="customization-options" tabindex="-1">Customization Options <a class="header-anchor" href="#customization-options" aria-label="Permalink to &quot;Customization Options&quot;">​</a></h2><p>You can configure the player behavior in <strong>Settings &gt; Video Player</strong>:</p><ul><li><strong>Autoplay:</strong> Start the video automatically when the page loads (Note: Browsers usually require &quot;Mute&quot; for this to work).</li><li><strong>Mute:</strong> Start the video with the sound off.</li><li><strong>Show Controls:</strong> Toggle the visibility of the YouTube player controls (Play/Pause, volume, etc.).</li><li><strong>Related Videos:</strong> Choose whether to show related videos from the same channel after the video ends.</li><li><strong>Modest Branding:</strong> Reduces the size of the YouTube logo in the control bar.</li></ul><h2 id="mobile-considerations" tabindex="-1">Mobile Considerations <a class="header-anchor" href="#mobile-considerations" aria-label="Permalink to &quot;Mobile Considerations&quot;">​</a></h2><p>On mobile devices, most browsers prevent autoplay to save data. TubeBay handles this gracefully by showing the video thumbnail with a play overlay, ensuring your users always have a clear call-to-action to watch the video.</p>',9)])])}const m=t(r,[["render",s]]);export{c as __pageData,m as default};
